@@ -361,6 +368,113 @@
 const IDLE_FRAMES_MAP: Record<CharacterType, string[][]> = {
   king: KING_IDLE_FRAMES,
   knight: KNIGHT_IDLE_FRAMES,
   healer: HEALER_IDLE_FRAMES,
   sentinel: SENTINEL_IDLE_FRAMES,
   nobility: NOBILITY_IDLE_FRAMES,
   squire: SQUIRE_IDLE_FRAMES,
   scribe: SCRIBE_IDLE_FRAMES,
   judge: JUDGE_IDLE_FRAMES,
   blacksmith: BLACKSMITH_IDLE_FRAMES,
 };

 const IDLE_FRAME_DURATION = 200;
+
+// ─── Walking animation frames ─────────────────────────────────────
+
+const KING_WALK_FRAMES = [
+  KING_SPRITE.map(line => line.replace(/B/g, 'b')), // legs forward
+  KING_SPRITE,
+  KING_SPRITE.map(line => line.replace(/B/g, 'B')), // legs backward (normal)
+  KING_SPRITE,
+];
+
+const KNIGHT_WALK_FRAMES = [
+  KNIGHT_SPRITE.map((line, i) => {
+    if (i >= 19 && i <= 22) {
+      return line.replace(/M/g, 'm'); // legs forward (darker)
+    }
+    return line;
+  }),
+  KNIGHT_SPRITE,
+  KNIGHT_SPRITE.map((line, i) => {
+    if (i >= 19 && i <= 22) {
+      return line.replace(/M/g, 'M'); // legs backward (normal)
+    }
+    return line;
+  }),
+  KNIGHT_SPRITE,
+];
+
+const HEALER_WALK_FRAMES = [
+  HEALER_SPRITE.map(line => line.replace(/B/g, 'b')),
+  HEALER_SPRITE,
+  HEALER_SPRITE.map(line => line.replace(/B/g, 'B')),
+  HEALER_SPRITE,
+];
+
+const SENTINEL_WALK_FRAMES = [
+  SENTINEL_SPRITE.map(line => line.replace(/B/g, 'b')),
+  SENTINEL_SPRITE,
+  SENTINEL_SPRITE.map(line => line.replace(/B/g, 'B')),
+  SENTINEL_SPRITE,
+];
+
+const NOBILITY_WALK_FRAMES = [
+  NOBILITY_SPRITE.map(line => line.replace(/B/g, 'b')),
+  NOBILITY_SPRITE,
+  NOBILITY_SPRITE.map(line => line.replace(/B/g, 'B')),
+  NOBILITY_SPRITE,
+];
+
+const SQUIRE_WALK_FRAMES = [
+  SQUIRE_SPRITE.map(line => line.replace(/B/g, 'b')),
+  SQUIRE_SPRITE,
+  SQUIRE_SPRITE.map(line => line.replace(/B/g, 'B')),
+  SQUIRE_SPRITE,
+];
+
+const SCRIBE_WALK_FRAMES = [
+  SCRIBE_SPRITE.map(line => line.replace(/B/g, 'b')),
+  SCRIBE_SPRITE,
+  SCRIBE_SPRITE.map(line => line.replace(/B/g, 'B')),
+  SCRIBE_SPRITE,
+];
+
+const JUDGE_WALK_FRAMES = [
+  JUDGE_SPRITE.map(line => line.replace(/B/g, 'b')),
+  JUDGE_SPRITE,
+  JUDGE_SPRITE.map(line => line.replace(/B/g, 'B')),
+  JUDGE_SPRITE,
+];
+
+const BLACKSMITH_WALK_FRAMES = [
+  BLACKSMITH_SPRITE.map(line => line.replace(/B/g, 'b')),
+  BLACKSMITH_SPRITE,
+  BLACKSMITH_SPRITE.map(line => line.replace(/B/g, 'B')),
+  BLACKSMITH_SPRITE,
+];
+
+const WALK_FRAMES_MAP: Record<CharacterType, string[][]> = {
+  king: KING_WALK_FRAMES,
+  knight: KNIGHT_WALK_FRAMES,
+  healer: HEALER_WALK_FRAMES,
+  sentinel: SENTINEL_WALK_FRAMES,
+  nobility: NOBILITY_WALK_FRAMES,
+  squire: SQUIRE_WALK_FRAMES,
+  scribe: SCRIBE_WALK_FRAMES,
+  judge: JUDGE_WALK_FRAMES,
+  blacksmith: BLACKSMITH_WALK_FRAMES,
+};
+
+// ─── Update movement with walk cycle advancement ───────────────────
+
+function updateMovement(cs: CharState, bounds: { x: number; y: number; w: number; h: number }) {
+  const dx = cs.tx - cs.x, dy = cs.ty - cs.y;
+  const dist = Math.sqrt(dx * dx + dy * dy);
+  if (dist > 2) {
+    cs.moving = true;
+    cs.x += (dx / dist) * 0.4;
+    cs.y += (dy / dist) * 0.4;
+    cs.wf = (cs.wf + 1) % WALK_FRAMES_MAP.knight.length; // advance walk frame cyclically
+    cs.dir = Math.abs(dx) > Math.abs(dy) ? (dx > 0 ? 'right' : 'left') : (dy > 0 ? 'down' : 'up');
+  } else {
+    cs.moving = false; cs.wf = 0; cs.idle--;
+    if (cs.idle <= 0) {
+      const mx = bounds.w * 0.15, my = bounds.h * 0.2;
+      cs.tx = bounds.x + mx + Math.random() * (bounds.w - mx * 2);
+      cs.ty = bounds.y + my + Math.random() * (bounds.h - my * 2);
+      cs.idle = 150 + Math.random() * 300;
+    }
+  }
+}
+
+// ─── Draw character with walking frames when moving ────────────────
+
+export function drawCharacter(
+  ctx: CanvasRenderingContext2D,
+  type: CharacterType,
+  state: AnimState,
+  x: number, y: number, s: number, frame: number,
+  agentId?: string,
+  currentJob?: string | null,
+) {
+  const id = agentId ?? `${type}-${Math.round(x)}`;
+  const palette = PALETTE_MAP[type];
+  const cs = getCS(id, x, y);
+  const bob = state === 'idle' ? Math.sin(frame * 0.05) * 1.2 : state === 'working' ? Math.sin(frame * 0.1) * 0.8 : 0;
+  const drawY = cs.y + bob;
+  const flipH = cs.dir === 'left';
+
+  // Select sprite frame based on movement and walk frame
+  let sprite: string[];
+  if (cs.moving) {
+    const walkFrames = WALK_FRAMES_MAP[type] || [SPRITE_MAP[type]];
+    const wfIndex = cs.wf % walkFrames.length;
+    sprite = walkFrames[wfIndex];
+  } else {
+    const idleFrames = IDLE_FRAMES_MAP[type] || [SPRITE_MAP[type]];
+    const idleIndex = Math.floor(frame / IDLE_FRAME_DURATION) % idleFrames.length;
+    sprite = idleFrames[idleIndex];
+  }
+
+  // Drop shadow
+  ctx.fillStyle = 'rgba(0,0,0,0.3)';
+  ctx.beginPath();
+  ctx.ellipse(cs.x + 8 * s, drawY + sprite.length * s + 2, 7 * s, 2 * s, 0, 0, Math.PI * 2);
+  ctx.fill();
+
+  drawSpriteDef(ctx, sprite, palette, cs.x, drawY, s, flipH);
+
+  drawStatusEffect(ctx, state, cs.x, drawY, s, frame);
+  if (agentId) {
+    updateBubble(id, state, currentJob ?? null, frame);
+    drawBubble(ctx, id, cs.x + 8 * s, drawY - 4);
+  }
+}
+
